"""Purge helpers for generated HDF5 plot JPG files."""

from __future__ import annotations

from dataclasses import dataclass
import re
from pathlib import Path
from typing import Any, Iterable


@dataclass(frozen=True)
class PlotTarget:
    """Registry entry describing JPG files generated by one plot method."""

    group: str
    method: str
    filename_var_part: str
    supports_filename_suffix: bool = False

    @property
    def qualified_name(self) -> str:
        """Return the group-qualified target name."""
        return f"{self.group}.{self.method}"


@dataclass
class PurgeResult:
    """Result returned by plot purge operations."""

    target: str
    matched_paths: list[Path]
    deleted_paths: list[Path]
    cancelled: bool = False


