COMPOSITE_TARGETS: dict[str, tuple[str, ...]] = {
    "single": tuple(target.qualified_name for target in SINGLE_TARGETS),
    "binary": tuple(target.qualified_name for target in BINARY_TARGETS),
    "hdf5": tuple(target.qualified_name for target in PLOT_TARGETS),
    "plot_hdf5_file": tuple(target.qualified_name for target in PLOT_TARGETS),
}


class PlotPurger:
    """Find, preview, and delete HDF5 plot JPG outputs."""

    def __init__(self, config: Any) -> None:
        self.config = config

    @classmethod
    def list_targets(cls) -> list[str]:
        """Return all supported purge target names."""
        composites = sorted(COMPOSITE_TARGETS)
        concrete = sorted(target.qualified_name for target in PLOT_TARGETS)
        return composites + concrete

    def preview(
        self,
        target: str,
        simu_name: str | None = None,
        plot_dir: str | Path | None = None,
        filename_suffix: str | None = None,
    ) -> PurgeResult:
        """Return files matching a purge target without deleting them."""
        paths = self._matched_paths(target, simu_name, plot_dir, filename_suffix)
        return PurgeResult(target=target, matched_paths=paths, deleted_paths=[], cancelled=False)

    def purge(
        self,
        target: str,
        simu_name: str | None = None,
        plot_dir: str | Path | None = None,
        filename_suffix: str | None = None,
        yes: bool = False,
    ) -> PurgeResult:
        """Preview and delete files for a purge target after confirmation."""
        preview = self.preview(target, simu_name, plot_dir, filename_suffix)
        print(self.format_preview(preview.matched_paths))
        if not preview.matched_paths:
            return preview

        expected_phrase = f"delete {len(preview.matched_paths)} files"
        if not yes:
            confirmation = input(f'Type "{expected_phrase}" to confirm: ')
            if confirmation != expected_phrase:
                return PurgeResult(
                    target=target,
                    matched_paths=preview.matched_paths,
                    deleted_paths=[],
                    cancelled=True,
                )

        deleted_paths: list[Path] = []
        for path in preview.matched_paths:
            path.unlink()
            deleted_paths.append(path)

        return PurgeResult(
            target=target,
            matched_paths=preview.matched_paths,
            deleted_paths=deleted_paths,
            cancelled=False,
        )

    @staticmethod
    def format_preview(paths: Iterable[Path], limit: int = 20) -> str:
        """Format a compact path preview with head and tail for long lists."""
        path_list = list(paths)
        lines = [f"Matched {len(path_list)} files"]
        if len(path_list) <= limit:
            shown_paths = path_list
        else:
            shown_paths = path_list[:10]
        lines.extend(str(path) for path in shown_paths)
        if len(path_list) > limit:
            omitted = len(path_list) - 20
            lines.append(f"... omitted {omitted} files ...")
            lines.extend(str(path) for path in path_list[-10:])
        return "\n".join(lines)

    def _matched_paths(
        self,
        target: str,
        simu_name: str | None,
        plot_dir: str | Path | None,
        filename_suffix: str | None,
    ) -> list[Path]:
        jpg_dir = self._jpg_dir(plot_dir)
        targets = self._expand_target(target)
        prefixes = self._prefixes_for(simu_name)

        matched: set[Path] = set()
        for target_entry in targets:
            for prefix in prefixes:
                pattern = self._pattern_for(prefix, target_entry, filename_suffix)
                matched.update(
                    path
                    for path in jpg_dir.glob(pattern)
                    if self._matches_filename(path.name, prefix, target_entry, filename_suffix)
                )

        safe_paths = [path.resolve() for path in matched if self._is_safe_jpg(path, jpg_dir)]
        return sorted(safe_paths)

    def _jpg_dir(self, plot_dir: str | Path | None) -> Path:
        root = Path(plot_dir if plot_dir is not None else self.config.plot_dir).expanduser()
        return (root / "jpg").resolve()

    def _prefixes_for(self, simu_name: str | None) -> list[str]:
        prefixes = self.config.figname_prefix
        if simu_name is not None:
            return [prefixes[simu_name]]
        return list(prefixes.values())

    def _expand_target(self, target: str) -> tuple[PlotTarget, ...]:
        if target in COMPOSITE_TARGETS:
            names = COMPOSITE_TARGETS[target]
            return tuple(self._target_by_name(name) for name in names)
        return (self._target_by_name(target),)

    def _target_by_name(self, target: str) -> PlotTarget:
        matches = [
            entry for entry in PLOT_TARGETS if target in {entry.qualified_name, entry.method}
        ]
        if len(matches) == 1:
            return matches[0]
        if not matches:
            raise ValueError(f"Unknown purge target: {target}")
        raise ValueError(
            f"Ambiguous purge target: {target}; use single.{target} or binary.{target}"
        )

    def _pattern_for(self, prefix: str, target: PlotTarget, filename_suffix: str | None) -> str:
        filename_part = target.filename_var_part
        if filename_suffix is not None:
            if not target.supports_filename_suffix:
                raise ValueError(f"{target.qualified_name} does not support filename_suffix")
            suffix = filename_suffix.strip("_")
            if suffix == "*":
                filename_part = f"{filename_part}_*"
            elif suffix:
                filename_part = f"{filename_part}_{suffix}"
        return f"{prefix}output_ttot_*_{filename_part}.jpg"

    def _matches_filename(
        self, name: str, prefix: str, target: PlotTarget, filename_suffix: str | None
    ) -> bool:
        filename_part = re.escape(target.filename_var_part)
        if filename_suffix is not None:
            if not target.supports_filename_suffix:
                raise ValueError(f"{target.qualified_name} does not support filename_suffix")
            suffix = filename_suffix.strip("_")
            if suffix == "*":
                filename_part = f"{filename_part}_[^/]*"
            elif suffix:
                filename_part = f"{filename_part}_{re.escape(suffix)}"
        pattern = rf"^{re.escape(prefix)}output_ttot_[^_]+_{filename_part}\.jpg$"
        return re.match(pattern, name) is not None

    @staticmethod
    def _is_safe_jpg(path: Path, jpg_dir: Path) -> bool:
        resolved = path.resolve()
        try:
            resolved.relative_to(jpg_dir)
        except ValueError:
            return False
        return resolved.is_file() and resolved.suffix == ".jpg"
